const opciones = this.frm_valores_asegurados_deducibles;
const numOpcion = Number.parseInt(this.tri_numero_opcion ?? 1, 10) || 1;

const toNumber = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : 0;
};

const normalizeText = (value) =>
  String(value ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim()
    .toLowerCase();

const formatNumberCO = (value) =>
  new Intl.NumberFormat("es-CO", { maximumFractionDigits: 0 }).format(toNumber(value));

if (Array.isArray(opciones)) {
  for (const row of opciones) {
    if (!row || typeof row !== "object") {
      continue;
    }

    const rowOpcion = normalizeText(row.frm_valores_opcion);
    const rowId = String(row.row_id ?? "").toLowerCase();
    const opPadded = String(numOpcion).padStart(2, "0");

    const isCurrentOption =
      rowOpcion === `opcion ${numOpcion}` ||
      rowId.includes(`opc_${opPadded}`) ||
      rowId.includes(`opc_${numOpcion}`) ||
      rowId.includes(`opc${numOpcion}`);

    if (!isCurrentOption) {
      continue;
    }

    const factor = normalizeText(row.frm_valores_deducible_minimo_factor).toUpperCase();

    if (factor === "SMMLV") {
      const smmlvCantidad = toNumber(row.frm_valores_deducible_minimo_smmlv);
      const salarioSmmlv = toNumber(this.salario_smmlv);
	  console.log(smmlvCantidad, salarioSmmlv);
      return formatNumberCO(smmlvCantidad * salarioSmmlv);
    }

    if (
      row.frm_valores_deducible_minimo_formateado != null &&
      row.frm_valores_deducible_minimo_formateado !== ""
    ) {
      return row.frm_valores_deducible_minimo_formateado;
    }

    return formatNumberCO(row.frm_valores_deducible_minimo);
  }
}

