try {
  const filas = Array.isArray(this.grd_coberturas_seleccionadas)
    ? this.grd_coberturas_seleccionadas
    : [];

  function esTrue(valor) {
    return valor === true || String(valor).toLowerCase() === "true";
  }

  function aNumero(valor) {
    if (valor === null || valor === undefined || valor === "") return 0;
    if (typeof valor === "number") return valor;
    const limpio = String(valor)
      .replace(/\s/g, "")
      .replace(/\$/g, "")
      .replace(/\./g, "")
      .replace(/,/g, ".");
    const num = parseFloat(limpio);
    return isNaN(num) ? 0 : num;
  }

  const seleccionadas = filas.filter(item => esTrue(item.frm_cobertura_seleccionada));

  if (seleccionadas.length === 0) {
    return "NO";
  }

  const todasValidas = seleccionadas.every(item => {
    const codigo = String(item.frm_cobertura_codigo || "").trim();

    // Regla 1: código "5" → no valida nada
    if (codigo === "5") {
      return true;
    }

    // Regla 2: código "3" → usa frm_cobertura_calculoDeducibleOpcion_2
    if (codigo === "3") {
      const opcion2 = String(item.frm_cobertura_calculoDeducibleOpcion_2 || "").trim().toUpperCase();

      // Si está vacío o NA → no valida
      if (opcion2 === "NA") return true;

      if (opcion2 === "VALOR") {
        return item.frm_cobertura_deducible_minimo_valor !== null &&
              item.frm_cobertura_deducible_minimo_valor !== undefined &&
              aNumero(item.frm_cobertura_deducible_minimo_valor) > 0;
      }

      if (opcion2 === "SMMLV") {
        return item.frm_cobertura_deducible_minimo !== null &&
              item.frm_cobertura_deducible_minimo !== undefined &&
              aNumero(item.frm_cobertura_deducible_minimo) > 0;
      }

      return false;
    }

    // Validación normal para el resto
    const opcion = item.frm_cobertura_calculoDeducibleOpcion;
    const tipo = String(opcion || "").trim().toUpperCase();

    if (tipo === "VALOR") {
      return item.frm_cobertura_deducible_minimo_valor !== null &&
             item.frm_cobertura_deducible_minimo_valor !== undefined &&
             aNumero(item.frm_cobertura_deducible_minimo_valor) > 0;
    }

    if (tipo === "SMMLV") {
      return item.frm_cobertura_deducible_minimo !== null &&
             item.frm_cobertura_deducible_minimo !== undefined &&
             aNumero(item.frm_cobertura_deducible_minimo) > 0;
    }

    return false;
  });

  return todasValidas ? "SI" : "NO";

} catch (e) {
  return "NO";
}

