try {
  const filas = Array.isArray(this.grd_coberturas_seleccionadas)
    ? this.grd_coberturas_seleccionadas
    : [];

  function esTrue(valor) {
    return valor === true || String(valor).toLowerCase() === "true";
  }

  // Campos de control a revisar por fila
  const camposControl = [
    'frm_cobertura_limite_aseg_vigencia_control',
    'frm_cobertura_limiteAseg_porcentaje_control',
    'frm_cobertura_limite_aseg_evento_control',
    'frm_cobertura_limite_aseg_evento_control_valor',
    'frm_control_maximo_deducible_minimo_coberturas',
    'frm_cobertura_deducible_minimo_control_excede_limite',
    'frm_cobertura_limite_aseg_vigencia_tipo_control_select',
    'frm_control_campo_cobertura_deducible_minimo_valor' 
  ];

  const seleccionadas = filas.filter(item => esTrue(item.frm_cobertura_seleccionada));

  if (seleccionadas.length === 0) {
    return "NO";
  }

  // Si alguna fila tiene al menos un campo de control con valor distinto de ""
  const hayObservacion = seleccionadas.some(item => {
    return camposControl.some(campo => {
      const valor = item[campo];
      return valor !== null &&
             valor !== undefined &&
             String(valor).trim() !== '';
    });
  });

  return hayObservacion ? "SI" : "NO";

} catch (e) {
  return "NO";
}

try {
  const filas = Array.isArray(this.grd_subcoberturas_seleccionadas)
    ? this.grd_subcoberturas_seleccionadas
    : [];

  // Campos de control a revisar por fila
  const camposControl = [
    'frm_cobertura_limite_aseg_vigencia_control',
    'frm_cobertura_limiteAseg_porcentaje_control',
    'frm_cobertura_limite_aseg_evento_control',
    'frm_cobertura_limite_aseg_evento_control_valor',
    'frm_control_maximo_deducible_minimo_coberturas',
    'frm_cobertura_deducible_minimo_control_excede_limite',
    'frm_cobertura_limite_aseg_vigencia_tipo_control_select',
    'frm_control_subcobertura_seleccionada',
    'frm_control_requerido_tipo_deducible',
    'frm_control_campo_cobertura_deducible_minimo_valor'
  ];

  // Solo revisar filas donde frm_cobertura_seleccionada_principal tenga valor
  const conPrincipal = filas.filter(item => {
    if (!item) return false;
    const principal = item.frm_cobertura_seleccionada_principal;
    return principal !== null &&
           principal !== undefined &&
           String(principal).trim() !== '';
  });

  if (conPrincipal.length === 0) {
    return "NO";
  }

  // Si alguna fila tiene al menos un campo de control con valor distinto de ""
  const hayObservacion = conPrincipal.some(item => {
    return camposControl.some(campo => {
      const valor = item[campo];
      return valor !== null &&
             valor !== undefined &&
             String(valor).trim() !== '';
    });
  });

  return hayObservacion ? "SI" : "NO";

} catch (e) {
  return "NO";
}
